insert into greendogops.person_recruiting as r (person_id, target_title, pipeline, stage, source, interview_date,  score, resume_url, keep_for_future, follow_up_date, status_notes, notes) values ('31796e92-7212-4520-9b91-534682030d7e', 'DVM', 'DVM Vet America', 'Offer Declined', 'Indeed', null, 5.0, null, null, null, '3/17/25_GF_ Emailed DVM open house email_____3/18/24 -GF - Offer declined - Offer made - She declnied - - - 3/6_NG, notes from Doc from call- WILL GET BACK TO ME (DOC) ON WHATS APP. VERY NICE. LOOKING FOR A MENTORSHIP TYPE OPPORTUNITY. TOLD HER OFFER WAS BASED ON HER ‘PACKAGE’ OF PTO VS CONT ED VS 4-5DAYS WORKED/ WEEK. INTERESTED IN 3-4 DAYS WORKING ‘SOLO’ SCHEDULE AND 1 DAY WORKING ALONGSIDE DVM. TOTAL OF 4-5 DAYS PER WEEK. 2 CONSECTIVE DAYS OFF AS OFTEN AS POSSIBLE. MENTORSHIP AND SUGICAL AND IMAGING EXPERIENCE IS IMPORTANT TO HER. $125-$140K / YEAR DEPENDING ON HER INDIVIDUAL PACKAGE. SHE IS VERY INTERESTED. NICE CANDIDATE. MOVING TO LA IN APRIL, WOULD WANT TO BEGIN THEN - 3/4/2024_NG call w/ Doc at 5:30pm- 3/1/2024_NG waiting for confirmation for a call with Doc on 3/1 or 3/4/20242/29_NG licensed in NY and lives there, planning on moving to LA mid April', null) on conflict (person_id) do update set target_title   = coalesce(excluded.target_title, r.target_title), pipeline       = coalesce(excluded.pipeline, r.pipeline), stage          = coalesce(excluded.stage, r.stage), source         = coalesce(excluded.source, r.source), interview_date = coalesce(excluded.interview_date, r.interview_date), score          = coalesce(excluded.score, r.score), resume_url     = excluded.resume_url, keep_for_future= coalesce(excluded.keep_for_future, r.keep_for_future), follow_up_date = coalesce(excluded.follow_up_date, r.follow_up_date), status_notes   = coalesce(excluded.status_notes, r.status_notes), notes          = coalesce(excluded.notes, r.notes);
